sequence.script:
var initPayload, treasuryData;
try {
    var ip = mc.getProperty("initialpayload");
    initPayload  = (typeof ip === "string") ? JSON.parse(ip) : ip;
    treasuryData = mc.getPayloadJSON(); // ← read GET response directly, no property needed
} catch(e) {
    throw new Error("Failed to parse properties: " + e.message);
}

var claimAmount = (initPayload && initPayload.payment && initPayload.payment.claimAmount)
                  ? Number(initPayload.payment.claimAmount) : 0;

var cashPos  = treasuryData && treasuryData.cashPosition;
var totBal   = cashPos && cashPos.totalBalance;
var oldTotal = totBal ? Number(totBal.amountValue) : 0;
var currency = totBal ? totBal.currencyCode : "";

var now = new Date().toISOString();

var body = {
    "reference": {},
    "cashPosition": {
        "previousBalance": {
            "amountValue":  oldTotal,
            "currencyCode": currency
        },
        "totalBalance": {
            "amountValue":  Number((oldTotal - claimAmount).toFixed(2)),
            "currencyCode": currency
        }
    },
    "lastUpdatedDateTime": now,
    "payoutDateTime":      now
};

mc.setPayloadJSON(body);
